class Solution {
    /**
     * Solves the problem by maintaining connectivity and parity information using a Disjoint Set Union (DSU) structure.
     * 
     * The condition that "the sum of edge weights in every cycle remains even" is equivalent to
     * stating that the graph must be bipartite when considering only the parities of path weights.
     * 
     * Specifically, if we assign a "parity" (0 or 1) to each node relative to a fixed reference node in its component,
     * then for any edge (u, v) with weight w:
     * 1. If u and v are in different components, the edge can be added.
     * 2. If u and v are in the same component, adding the edge creates a cycle. 
     *    The cycle's weight parity is (path_weight(u, v) + w) mod 2. 
     *    For the cycle weight to be even (parity 0), we need:
     *    (parity_u ^ parity_v ^ w) mod 2 = 0, or parity_u ^ parity_v = w mod 2.
     *    If this condition is met, the edge is redundant for parity constraints (it closes a cycle with even weight).
     *    If this condition is NOT met, adding the edge creates an odd-weight cycle, so it is rejected.
     * 
     * We use DSU where each node stores its parent and the parity difference (xoring the weights) 
     * relative to its immediate parent.
     */
    static class DSU {
        int[] parent;
        // parity[i] stores the parity of the path weight from node i to its current representative parent[i]
        int[] parity; 
        int n;

        public DSU(int n) {
            this.n = n;
            parent = new int[n];
            parity = new int[n];
            for (int i = 0; i < n; i++) {
                parent[i] = i;
                parity[i] = 0; // Distance to self is 0
            }
        }

        /**
         * Finds the representative (root) of the set containing i, and performs path compression.
         * Updates parity[i] to store the parity of the path from i to the root.
         * @param i The node index.
         * @return The root of the set containing i.
         */
        public int find(int i) {
            if (parent[i] == i) {
                return i;
            }

            int root = find(parent[i]);
            // Update parity[i]: new_parity[i] = old_parity[i] XOR old_parity[parent[i]]
            parity[i] = parity[i] ^ parity[parent[i]];
            parent[i] = root;
            return root;
        }

        /**
         * Unites the sets containing u and v using the edge weight w.
         * @param u Node u.
         * @param v Node v.
         * @param w Edge weight (0 or 1).
         * @return true if the edge was added (u and v were in different components), false otherwise (cycle formed).
         */
        public boolean union(int u, int v, int w) {
            int rootU = find(u);
            int rootV = find(v);

            if (rootU != rootV) {
                // Different components: Add the edge. Merge V's tree into U's tree (arbitrarily).
                parent[rootV] = rootU;

                // We need to set parity[rootV] such that the path from rootV to rootU has the correct parity.
                // Path: rootV -> v --(w)--> u -> rootU
                // We know:
                // 1. parity[u] = path_parity(u, rootU)
                // 2. parity[v] = path_parity(v, rootV)
                // 3. w = path_parity(u, v)
                // We want path_parity(rootV, rootU) = parity[rootV]
                // Path parity (rootV -> rootU) = path_parity(rootV -> v) ^ w ^ path_parity(u -> rootU)
                // path_parity(rootV -> v) = parity[v]
                // path_parity(u -> rootU) = parity[u]

                // parity[rootV] (the new link) = parity[v] ^ w ^ parity[u]
                parity[rootV] = parity[v] ^ w ^ parity[u];
                return true;
            } else {
                // Same component: Check for an odd cycle.
                // The cycle is formed by path(u, rootU) + path(v, rootU) + edge(u, v).
                // Path parity (u -> v) through existing tree structure: parity[u] ^ parity[v]
                // Cycle parity = (parity[u] ^ parity[v]) ^ w

                // Condition for NO odd cycle (cycle weight is even):
                // (parity[u] ^ parity[v]) ^ w == 0
                if ((parity[u] ^ parity[v]) == w) {
                    // Cycle weight is even. Accept the edge (it doesn't violate the condition).
                    // Since it's already connected, we don't change the DSU structure.
                    return true; 
                } else {
                    // Cycle weight is odd. Reject the edge.
                    return false;
                }
            }
        }
    }


