        if (n < 3) return 0; // Constraint says n >= 3, but good practice.
        int N = (int) n;

        DSU dsu = new DSU(N);
        int addedEdgesCount = 0;

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int w = (int) edge[2];

            // The union function handles both adding the edge (if roots differ) 
            // and checking the cycle condition (if roots are the same).
            if (dsu.union(u, v, w)) {
                // If union returns true, it means the edge was either added (new component) 
                // or it closed an even cycle (allowed).
                // We only increment the count if the edge was actually added to form a new connection/structure,
                // or if the problem interpretation requires counting all edges that *don't* create an odd cycle.

                // Re-reading the requirement: "if ... the sum ... is even, then add this edge."
                // If roots are different, we add it, and it is successful.
                // If roots are the same, we add it only if the cycle is even.

                int rootU = dsu.find(u);
                int rootV = dsu.find(v);

                if (rootU != rootV) {
                    // New edge successfully added
                    addedEdgesCount++;
                } else {
                    // Same component. If union returned true, the cycle was even, so we add it.
                    // We must count it even if it closes an even cycle.
                    // The union function returns true if the edge is accepted (either by joining or by even cycle).
                    addedEdgesCount++;
                }
            }
        }

        return addedEdgesCount;
    }
